var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 꿈에서 본 별똥별을 쫓다가 그곳에 다다랐다.","JPN":"僕は夢で見た流れ星を追いかけて、そこに辿り着いた。","ENG":"In my dream, I chased a shooting star, and reached a certain place.","TWN":"我在夢裡追著流星，追著追著便來到那裡。"},"stage":{"bg":"NANAHARA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"잔잔한 바람에 벚꽃이 휘날리던.","JPN":"穏やかな風に桜が舞い散った。","ENG":"Cherry blossoms fluttered in the gentle wind.","TWN":"一個櫻花在微風中飄揚。"},"stage":{"bg":"NANAHARA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"벚나무의 향기가 가득한 장소.","JPN":"桜の匂いに満ちた場所。","ENG":"The air was so fragrant.","TWN":"充滿櫻花香氣的地方。"},"stage":{"bg":"NANAHARA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그날 만난 소녀는… 나와 다른 세상에 있는 사람 같았다.","JPN":"あの日出会った少女は……\\n僕とは異なる世界を生きる人のようだった。","ENG":"The girl I met that day... She looked as if she was from another world.","TWN":"那天見到的少女… 感覺和我是不同世界的人。"},"stage":{"bg":"NANAHARA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마치 꿈을 꾸고 있는 것처럼.","JPN":"まるで夢を見ているかのように。","ENG":"Like a dream...","TWN":"就像在做夢一樣。"},"stage":{"bg":"NANAHARA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리는 각자 다른 곳을 바라보고 있었다.","JPN":"僕たちはそれぞれ違う場所を見つめていた。","ENG":"We were looking at different places.","TWN":"我們各自看著不同的地方。"},"stage":{"bg":"NANAHARA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너는……?","JPN":"君は……？","ENG":"You are...","TWN":"你是……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"침식체에게 입은 상처군요.","JPN":"侵食体による傷ですね。","ENG":"This is a wound from a C.O.","TWN":"這是侵蝕體造成的傷口。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"상처는 깊지 않지만, <color=#ffd34c>독</color>은 이미 혈관을 타고 스며들었습니다.","JPN":"傷は深くありませんが、<color=#ffd34c>毒</color>がすでに血管から浸透しています。","ENG":"It’s not deep, but the <color=#ffd34c>poison</color> is already flowing in her veins.","TWN":"傷口不深，但<color=#ffd34c>毒</color>已經藉由血管滲入。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이로하의 상처가…… 아물고 있어.","JPN":"いろはの傷が……治っている。","ENG":"The cut... It’s closing.","TWN":"伊呂波的傷口…… 正在癒合。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치유 능력을 가진 카운터였구나. 다행이다.","JPN":"治癒能力のカウンターだったんだね。よかった。","ENG":"You’re a Counter with healing power. Thank you.","TWN":"原來是有治癒能力的制裁者，真是太好了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안심하기엔 아직 일러요. 독이 퍼지지 않게 조치했지만 이것만으론 부족합니다.","JPN":"安心するにはまだ早いです。\\n毒が広がらないように処置しましたが、これだけでは足りません。","ENG":"Don’t thank me yet. I only stopped the poison from spreading, but this is not enough.","TWN":"還不能放心。雖然有先做一些處理防止毒性擴散，但光這樣是不夠的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"독기의 원흉이 건재한 이상, 이미 혈관에 퍼진 독을 정화할 방법은 없으니까요.","JPN":"毒の元凶が健在である以上、\\nすでに血管に広がった毒を浄化する方法はありませんから。","ENG":"As long as the source of the poison is still out there, you can’t remove what’s already inside her body.","TWN":"只要毒根還在，就沒有辦法淨化已經擴散到血管的毒。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"독이라고? 1종 침식체한테 그런 게 있었어?","JPN":"毒？　第1種侵食体にそんな能力があるのか？","ENG":"Poison? I didn’t know Category 1 C.O.s were poisonous.","TWN":"毒？1類侵蝕體有毒嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 본래는 없습니다. 그 때문에 그대를 찾아온 것이죠.","JPN":"はい、本来はございません。ですので、貴方を訪ねて来たのです。","ENG":"Normally they aren’t. That’s why I came here to see you.","TWN":"對，本來是沒有的，所以才會來找你。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나를……?","JPN":"僕を……？","ENG":"See me?","TWN":"找我……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"인사가 늦었군요. 나나하라 가문의 당주, 나나하라 치나츠라고 합니다.","JPN":"ご挨拶が遅れました。七原家の当主、七原千夏と申します。","ENG":"Let me introduce myself. I’m Nanahara Chinatsu, the leader of the Nanahara family.","TWN":"還沒介紹，我是七原家族的堂主七原千夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그간 무탈히 지내셨나요, 미나토 님.","JPN":"お変わりございませんでしたか、湊様。","ENG":"How have you been, Mr. Nayuka.","TWN":"別來無恙，南裕夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};